mapper.update:
UPDATE products SET category_id = #{category_id}, name = #{name}, description = #{description}, price = #{price},
sale_price_updated_at = CASE WHEN sale_price != #{sale_price} THEN CURRENT_TIMESTAMP ELSE sale_price_updated_at END,
sale_price = #{sale_price}, stock = #{stock}, delivery_fee = #{delivery_fee}, free_shipping = #{free_shipping}, status = #{status}, image_l = #{image_l}, image_s = #{image_s}, updated_at = CURRENT_TIMESTAMP WHERE product_id = #{product_id}

mapper.select:
SELECT *
FROM products
WHERE status = 'APPROVED'
  AND (
        category_id = #{category_id}
        OR category_id IN (
            SELECT category_id
            FROM categories
            WHERE parent_id = #{category_id}
        )
  )
ORDER BY product_id DESC
LIMIT #{start}, #{blockList}

SELECT COUNT(*)
FROM products
WHERE status = 'APPROVED'
  AND (
        category_id = #{category_id}
        OR category_id IN (
            SELECT category_id
            FROM categories
            WHERE parent_id = #{category_id}
        )
  )
